1	export class MarsRover {
2	  private static readonly LEFT_TURNS: Record<string, string> = {
3	    N: "W",
4	    W: "S",
5	    S: "E",
6	    E: "N",
7	  };
8	
9	  private static readonly RIGHT_TURNS: Record<string, string> = {
10	    N: "E",
11	    E: "S",
12	    S: "W",
13	    W: "N",
14	  };
15	
16	  private static readonly MOVEMENT_DELTAS: Record<string, { dx: number; dy: number }> = {
17	    N: { dx: 0, dy: 1 },
18	    E: { dx: 1, dy: 0 },
19	    S: { dx: 0, dy: -1 },
20	    W: { dx: -1, dy: 0 },
21	  };
22	
23	  private static readonly COMMAND_HANDLERS: Record<string, (rover: MarsRover) => void> = {
24	    L: (rover) => rover.rotateLeft(),
25	    R: (rover) => rover.rotateRight(),
26	    F: (rover) => rover.moveForward(),
27	  };
28	
29	  constructor(
30	    public x: number,
31	    public y: number,
32	    public heading: string,
33	  ) {}
34	
35	  rotateLeft(): void {
36	    const newHeading = MarsRover.LEFT_TURNS[this.heading];
37	    if (newHeading) {
38	      this.heading = newHeading;
39	    }
40	  }
41	
42	  rotateRight(): void {
43	    const newHeading = MarsRover.RIGHT_TURNS[this.heading];
44	    if (newHeading) {
45	      this.heading = newHeading;
46	    }
47	  }
48	
49	  moveForward(): void {
50	    const delta = MarsRover.MOVEMENT_DELTAS[this.heading];
51	    if (delta) {
52	      this.x += delta.dx;
53	      this.y += delta.dy;
54	    }
55	  }
56	
57	  execute(command: string): void {
58	    const handler = MarsRover.COMMAND_HANDLERS[command];
59	    if (handler) {
60	      handler(this);
61	    }
62	  }
63	}
